<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: system-ui, -apple-system, sans-serif; background: #f5f5f5; color: #222; padding: 1rem; max-width: 800px; margin: 0 auto; }
  h1 { margin-bottom: 1rem; font-size: 1.4rem; }
  h2 { font-size: 1.1rem; margin: 1.5rem 0 0.5rem; }

  /* Form */
  .entry-form { background: #fff; padding: 1rem; border-radius: 6px; border: 1px solid #ddd; display: flex; flex-wrap: wrap; gap: 0.5rem; align-items: flex-end; }
  .form-group { display: flex; flex-direction: column; gap: 0.2rem; }
  .form-group label { font-size: 0.8rem; font-weight: 600; color: #555; }
  input, select { padding: 0.4rem 0.5rem; border: 1px solid #bbb; border-radius: 4px; font-size: 0.9rem; }
  input:focus, select:focus { outline: none; border-color: #4a90d9; box-shadow: 0 0 0 2px rgba(74,144,217,0.2); }
  #amount { width: 110px; }
  #category { width: 130px; }
  #date { width: 150px; }
  #note { flex: 1; min-width: 120px; }
  #add-expense { padding: 0.4rem 1rem; background: #4a90d9; color: #fff; border: none; border-radius: 4px; cursor: pointer; font-size: 0.9rem; font-weight: 600; }
  #add-expense:hover { background: #357abd; }

  /* Error */
  #form-error { color: #c0392b; font-size: 0.85rem; min-height: 1.2em; padding: 0.2rem 0; width: 100%; }

  /* Filters */
  .filters { background: #fff; padding: 0.75rem 1rem; border-radius: 6px; border: 1px solid #ddd; display: flex; flex-wrap: wrap; gap: 0.5rem; align-items: center; margin-top: 1rem; }
  .filters label { font-size: 0.8rem; font-weight: 600; color: #555; }

  /* Summary */
  .summary-bar { display: flex; gap: 1rem; flex-wrap: wrap; margin-top: 1rem; align-items: center; }
  .total-box { background: #2c3e50; color: #fff; padding: 0.6rem 1.2rem; border-radius: 6px; font-size: 1.1rem; font-weight: 700; }
  .cat-totals { display: flex; gap: 0.5rem; flex-wrap: wrap; }
  .cat-total { background: #eaf2fb; padding: 0.3rem 0.7rem; border-radius: 4px; font-size: 0.85rem; color: #2c3e50; font-weight: 600; }

  /* Expense list */
  .expense-list { margin-top: 1rem; }
  .expense { display: flex; align-items: center; justify-content: space-between; background: #fff; padding: 0.6rem 1rem; border-radius: 4px; border-bottom: 1px solid #eee; font-size: 0.9rem; }
  .expense:last-child { border-bottom: none; }
  .exp-left { display: flex; gap: 1rem; align-items: center; flex-wrap: wrap; }
  .exp-amount { font-weight: 700; color: #2c3e50; min-width: 80px; }
  .exp-category { background: #eee; padding: 0.15rem 0.5rem; border-radius: 3px; font-size: 0.8rem; text-transform: capitalize; }
  .exp-date { color: #777; font-size: 0.8rem; }
  .exp-note { color: #999; font-style: italic; font-size: 0.8rem; }
  .exp-del { background: none; border: 1px solid #e74c3c; color: #e74c3c; padding: 0.2rem 0.6rem; border-radius: 4px; cursor: pointer; font-size: 0.8rem; }
  .exp-del:hover { background: #e74c3c; color: #fff; }

  .empty-msg { text-align: center; color: #999; padding: 2rem; font-style: italic; }
</style>
</head>
<body>

<h1>💰 Expense Tracker</h1>

<!-- Entry Form -->
<form id="expense-form" autocomplete="off">
  <div class="entry-form">
    <div class="form-group">
      <label for="amount">Amount</label>
      <input type="number" id="amount" step="0.01" placeholder="0.00">
    </div>
    <div class="form-group">
      <label for="category">Category</label>
      <select id="category">
        <option value="">— select —</option>
        <option value="groceries">groceries</option>
        <option value="transport">transport</option>
        <option value="bills">bills</option>
        <option value="fun">fun</option>
      </select>
    </div>
    <div class="form-group">
      <label for="date">Date</label>
      <input type="date" id="date">
    </div>
    <div class="form-group">
      <label for="note">Note (optional)</label>
      <input type="text" id="note" placeholder="e.g. weekly shop">
    </div>
    <button type="submit" id="add-expense">Add Expense</button>
  </div>
  <div id="form-error"></div>
</form>

<!-- Filters -->
<div class="filters">
  <div class="form-group">
    <label for="filter-category">Category</label>
    <select id="filter-category">
      <option value="all">all</option>
      <option value="groceries">groceries</option>
      <option value="transport">transport</option>
      <option value="bills">bills</option>
      <option value="fun">fun</option>
    </select>
  </div>
  <div class="form-group">
    <label for="filter-from">From</label>
    <input type="date" id="filter-from">
  </div>
  <div class="form-group">
    <label for="filter-to">To</label>
    <input type="date" id="filter-to">
  </div>
</div>

<!-- Summary -->
<div class="summary-bar">
  <div class="total-box">Total: <span id="total">0.00</span></div>
  <div class="cat-totals" id="cat-totals"></div>
</div>

<!-- Expense List -->
<h2>Expenses</h2>
<div class="expense-list" id="expense-list"></div>

<script>
(function() {
  // --- State ---
  var STORAGE_KEY = 'expense_tracker_data';
  var categories = ['groceries', 'transport', 'bills', 'fun'];

  function loadExpenses() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      return raw ? JSON.parse(raw) : [];
    } catch(e) {
      return [];
    }
  }

  function saveExpenses(expenses) {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
  }

  var expenses = loadExpenses();

  // --- DOM refs ---
  var form = document.getElementById('expense-form');
  var amountInput = document.getElementById('amount');
  var categorySelect = document.getElementById('category');
  var dateInput = document.getElementById('date');
  var noteInput = document.getElementById('note');
  var addBtn = document.getElementById('add-expense');
  var formError = document.getElementById('form-error');

  var filterCategory = document.getElementById('filter-category');
  var filterFrom = document.getElementById('filter-from');
  var filterTo = document.getElementById('filter-to');

  var totalEl = document.getElementById('total');
  var catTotalsEl = document.getElementById('cat-totals');
  var expenseListEl = document.getElementById('expense-list');

  // Set default date to today
  dateInput.value = new Date().toISOString().slice(0, 10);

  // --- Validation & Add ---
  form.addEventListener('submit', function(e) {
    e.preventDefault();
    formError.textContent = '';

    var amountVal = amountInput.value.trim();
    var catVal = categorySelect.value;
    var dateVal = dateInput.value.trim();

    // Validate amount
    if (amountVal === '' || isNaN(Number(amountVal)) || Number(amountVal) <= 0) {
      formError.textContent = 'Please enter a valid positive amount.';
      return;
    }

    // Validate date
    if (!dateVal) {
      formError.textContent = 'Please select a date.';
      return;
    }

    var expense = {
      id: Date.now() + '_' + Math.random().toString(36).substr(2, 5),
      amount: parseFloat(Number(amountVal).toFixed(2)),
      category: catVal || 'groceries',
      date: dateVal,
      note: noteInput.value.trim(),
      createdAt: Date.now()
    };

    expenses.push(expense);
    saveExpenses(expenses);

    // Reset amount field only
    amountInput.value = '';
    noteInput.value = '';
    categorySelect.value = '';
    dateInput.value = new Date().toISOString().slice(0, 10);

    render();
  });

  // --- Delete ---
  expenseListEl.addEventListener('click', function(e) {
    if (e.target.classList.contains('exp-del')) {
      var id = e.target.getAttribute('data-id');
      expenses = expenses.filter(function(exp) { return exp.id !== id; });
      saveExpenses(expenses);
      render();
    }
  });

  // --- Filters ---
  filterCategory.addEventListener('change', render);
  filterFrom.addEventListener('change', render);
  filterTo.addEventListener('change', render);

  // --- Render ---
  function getFiltered() {
    var fCat = filterCategory.value;
    var fFrom = filterFrom.value;
    var fTo = filterTo.value;

    return expenses.filter(function(exp) {
      if (fCat !== 'all' && exp.category !== fCat) return false;
      if (fFrom && exp.date < fFrom) return false;
      if (fTo && exp.date > fTo) return false;
      return true;
    });
  }

  function render() {
    var filtered = getFiltered();

    // Sort newest first by createdAt, then by date descending as tiebreaker
    filtered.sort(function(a, b) {
      if (b.createdAt !== a.createdAt) return b.createdAt - a.createdAt;
      return b.date.localeCompare(a.date);
    });

    // Total
    var total = 0;
    for (var i = 0; i < filtered.length; i++) {
      total += filtered[i].amount;
    }
    totalEl.textContent = total.toFixed(2);

    // Per-category totals
    catTotalsEl.innerHTML = '';
    categories.forEach(function(cat) {
      var catSum = 0;
      for (var j = 0; j < filtered.length; j++) {
        if (filtered[j].category === cat) catSum += filtered[j].amount;
      }
      if (catSum > 0 || true) { // show all categories even if zero? Let's show only non-zero for cleanliness, but spec says "one element per category"
        var el = document.createElement('div');
        el.className = 'cat-total';
        el.setAttribute('data-cat', cat);
        el.textContent = cat + ': ' + catSum.toFixed(2);
        catTotalsEl.appendChild(el);
      }
    });

    // Expense list
    expenseListEl.innerHTML = '';
    if (filtered.length === 0) {
      expenseListEl.innerHTML = '<div class="empty-msg">No expenses to show.</div>';
      return;
    }

    for (var k = 0; k < filtered.length; k++) {
      var exp = filtered[k];
      var row = document.createElement('div');
      row.className = 'expense';

      var left = document.createElement('div');
      left.className = 'exp-left';

      var amtEl = document.createElement('span');
      amtEl.className = 'exp-amount';
      amtEl.textContent = exp.amount.toFixed(2);

      var catEl = document.createElement('span');
      catEl.className = 'exp-category';
      catEl.textContent = exp.category;

      var dateEl = document.createElement('span');
      dateEl.className = 'exp-date';
      dateEl.textContent = exp.date;

      left.appendChild(amtEl);
      left.appendChild(catEl);
      left.appendChild(dateEl);

      if (exp.note) {
        var noteEl = document.createElement('span');
        noteEl.className = 'exp-note';
        noteEl.textContent = '"' + exp.note + '"';
        left.appendChild(noteEl);
      }

      row.appendChild(left);

      var delBtn = document.createElement('button');
      delBtn.className = 'exp-del';
      delBtn.setAttribute('data-id', exp.id);
      delBtn.textContent = '✕ Delete';
      row.appendChild(delBtn);

      expenseListEl.appendChild(row);
    }
  }

  // Initial render
  render();
})();
</script>
</body>
</html>
